<?php
namespace App\Services;
use App\Jobs\ProcessReportExportJob;use App\Models\{ReportExport,User};use App\Support\CurrentWorkspace;use Illuminate\Support\Facades\Storage;
class ExportService{public const REPORTS=['task_status'=>'taskStatusReport','overdue_tasks'=>'overdueTaskReport','no_update_tasks'=>'noUpdateTaskReport','proof_pending'=>'proofPendingReport','approval_pending'=>'approvalPendingReport','daily_submissions'=>'dailyReportSubmissionReport','missing_reports'=>'missingReportReport','employee_performance'=>'employeePerformanceReport','team_performance'=>'teamPerformanceReport','ai_weekly_summary'=>'aiWeeklySummaryReport'];public function __construct(private CurrentWorkspace $cw,private ReportService $reports){}public function requestExport(string $reportKey,array $filters,string $format,User $user):ReportExport{abort_unless(isset(self::REPORTS[$reportKey])&&in_array($format,['pdf','xlsx','csv'],true),422);$e=ReportExport::create(['workspace_id'=>$this->cw->required()->id,'user_id'=>$user->id,'report_key'=>$reportKey,'filters'=>$filters,'format'=>$format,'status'=>'pending','file_disk'=>'local']);ProcessReportExportJob::dispatch($e);return $e;}public function processExport(ReportExport $export):void{$export->update(['status'=>'processing','started_at'=>now()]);try{$method=self::REPORTS[$export->report_key];$data=$this->reports->$method($export->filters??[]);$this->storeExportFile($export,$data);$export->update(['status'=>'completed','completed_at'=>now()]);}catch(\Throwable $e){$export->update(['status'=>'failed','error_message'=>$e->getMessage(),'completed_at'=>now()]);throw $e;}}public function storeExportFile(ReportExport $export,mixed $data):void{$rows=collect(method_exists($data,'items')?$data->items():$data)->map(fn($r)=>json_encode($r instanceof \Illuminate\Database\Eloquent\Model?$r->toArray():(array)$r));$content=$export->format==='csv'?$rows->implode("\n"):"NAXAS WorkProof {$export->report_key} export\n\n".$rows->implode("\n");$path="workspaces/{$export->workspace_id}/exports/report-{$export->id}.{$export->format}";Storage::disk('local')->put($path,$content);$export->update(['file_path'=>$path,'file_disk'=>'local']);}}
